/// <summary>
///
/// </summary>
/// <param name="_sender"></param>
/// <param name="_eventArgs"></param>
[DataEventHandler(tableStr(GeneralJournalAccountEntry), DataEventType::PostedLoad)]
public static void GeneralJournalAccountEntry_onPostedLoad(Common _sender, DataEventArgs _eventArgs)
{
    GeneralJournalAccountEntry gjAccountEntry = _sender as GeneralJournalAccountEntry;
    GeneralJournalEntry gjEntry;
    VendInvoiceJour vendInvoiceJour;
    VendInvoiceInfoTable vendInvoiceInfoTable;
    LedgerJournalTable ledgerJournalTable;
    LedgerJournalTrans ledgerJournalTrans;

    if (!gjAccountEntry)
    return; // Safety check

    // Select the related GeneralJournalEntry
    select firstOnly gjEntry
    where gjEntry.RecId == gjAccountEntry.GeneralJournalEntry;

    if (gjEntry.SubledgerVoucherDataAreaId == "O051") // Use dataAreaId to check legal entity
    {
        // Select the related VendInvoiceJour
        select firstOnly vendInvoiceJour
        where vendInvoiceJour.LedgerVoucher == gjEntry.SubledgerVoucher;

        if (vendInvoiceJour)
        {
            select firstOnly vendInvoiceInfoTable
            where vendInvoiceInfoTable.PurchId == vendInvoiceJour.PurchId;

            if (vendInvoiceInfoTable)
            {
                gjAccountEntry.Text = vendInvoiceInfoTable.Description;
            }
        }

        select firstOnly ledgerJournalTrans
    where ledgerJournalTrans.Voucher == gjEntry.SubledgerVoucher;

        if (ledgerJournalTrans)
        {
            select firstOnly ledgerJournalTable
        where ledgerJournalTable.JournalNum == ledgerJournalTrans.JournalNum;

            if (ledgerJournalTable.JournalType == LedgerJournalType::VendInvoiceRegister)
            {
                gjAccountEntry.Text = ledgerJournalTrans.Txt;
            }
        }

    }
}

